import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const SprintDetail = () => {
  const { id } = useParams();
  const { user } = useContext(AuthContext);
  const [sprint, setSprint] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [retrospective, setRetrospective] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSprintData();
  }, [id]);

  const fetchSprintData = async () => {
    try {
      const response = await api.get(`/sprints/${id}`);
      setSprint(response.data.sprint);
      setTasks(response.data.tasks || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching sprint data:', error);
      setLoading(false);
    }
  };

  const handleCompleteSprint = async () => {
    if (!window.confirm('Mark this sprint as completed?')) return;

    try {
      await api.post(`/sprints/${id}/complete`);
      fetchSprintData();
    } catch (error) {
      alert(error.response?.data?.message || 'Error completing sprint');
    }
  };

  const handleGenerateRetrospective = async () => {
    try {
      const response = await api.get(`/ai/retrospective/${id}`);
      setRetrospective(response.data);
    } catch (error) {
      alert(error.response?.data?.message || 'Error generating retrospective');
    }
  };

  if (loading) {
    return <div className="loading">Loading sprint...</div>;
  }

  if (!sprint) {
    return <div className="alert alert-error">Sprint not found</div>;
  }

  const completedTasks = tasks.filter(t => t.status === 'Completed').length;
  const completionRate = tasks.length > 0 ? (completedTasks / tasks.length) * 100 : 0;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <div>
          <h1>{sprint.name}</h1>
          <p>Project: {sprint.projectId?.name || 'N/A'}</p>
        </div>
        <div>
          <Link to="/sprints" className="btn btn-secondary">Back to Sprints</Link>
          {user.role === 'PM' && sprint.status !== 'Completed' && (
            <button onClick={handleCompleteSprint} className="btn btn-success" style={{ marginLeft: '10px' }}>
              Complete Sprint
            </button>
          )}
          {user.role === 'PM' && sprint.status === 'Completed' && (
            <button onClick={handleGenerateRetrospective} className="btn btn-primary" style={{ marginLeft: '10px' }}>
              Generate Retrospective
            </button>
          )}
        </div>
      </div>

      <div className="card">
        <div className="card-header">Sprint Information</div>
        <p><strong>Status:</strong> <span className={`badge badge-${sprint.status === 'Completed' ? 'success' : sprint.status === 'Active' ? 'info' : 'warning'}`}>{sprint.status}</span></p>
        <p><strong>Start Date:</strong> {new Date(sprint.startDate).toLocaleDateString()}</p>
        <p><strong>End Date:</strong> {new Date(sprint.endDate).toLocaleDateString()}</p>
        <p><strong>Planned Velocity:</strong> {sprint.plannedVelocity} story points</p>
        <p><strong>Actual Velocity:</strong> {sprint.actualVelocity || 'Not completed'} story points</p>
        <p><strong>AI Predicted Capacity:</strong> {sprint.aiPredictedCapacity || 'N/A'} story points</p>
        <p><strong>Sprint Health Score:</strong> {sprint.sprintHealthScore || 'N/A'}%</p>
      </div>

      {sprint.aiRecommendation && (
        <div className="card">
          <div className="card-header">AI Recommendation</div>
          <div className="ai-recommendation">
            <p><strong>Predicted Capacity:</strong> {sprint.aiRecommendation.predictedCapacity} story points</p>
            <p><strong>Overload Warning:</strong> {sprint.aiRecommendation.overloadWarning ? 'Yes' : 'No'}</p>
            <p style={{ whiteSpace: 'pre-line' }}>{sprint.aiRecommendation.explanation}</p>
            <p><strong>Human Decision:</strong> {sprint.aiRecommendation.humanDecision}</p>
          </div>
        </div>
      )}

      {retrospective && (
        <div className="card">
          <div className="card-header">AI-Generated Sprint Retrospective</div>
          <div style={{ marginBottom: '20px' }}>
            <h4>Metrics</h4>
            <ul>
              <li>Planned Velocity: {retrospective.metrics.plannedVelocity}</li>
              <li>Actual Velocity: {retrospective.metrics.actualVelocity}</li>
              <li>Velocity Difference: {retrospective.metrics.velocityDifference > 0 ? '+' : ''}{retrospective.metrics.velocityDifference}</li>
              <li>Completion Rate: {retrospective.metrics.completionRate.toFixed(1)}%</li>
              <li>Sprint Health Score: {retrospective.metrics.sprintHealthScore}%</li>
            </ul>
          </div>

          <div style={{ marginBottom: '20px' }}>
            <h4>Insights</h4>
            {retrospective.insights.map((insight, idx) => (
              <div key={idx} className={`alert alert-${insight.type === 'success' ? 'success' : insight.type === 'warning' ? 'warning' : 'info'}`}>
                <strong>{insight.title}</strong>
                <p>{insight.message}</p>
              </div>
            ))}
          </div>

          {retrospective.recommendations.length > 0 && (
            <div>
              <h4>Recommendations</h4>
              {retrospective.recommendations.map((rec, idx) => (
                <div key={idx} style={{ marginBottom: '10px', padding: '10px', background: '#f8f9fa', borderRadius: '4px' }}>
                  <strong>{rec.category}:</strong> {rec.recommendation}
                  <span className={`badge badge-${rec.priority === 'High' ? 'danger' : rec.priority === 'Medium' ? 'warning' : 'info'}`} style={{ marginLeft: '10px' }}>
                    {rec.priority}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      <div className="card">
        <div className="card-header">Tasks ({tasks.length})</div>
        <p>Completion Rate: {completionRate.toFixed(1)}%</p>
        {tasks.length === 0 ? (
          <p>No tasks in this sprint. {user.role === 'PM' && <Link to="/tasks">Create one</Link>}</p>
        ) : (
          <table className="table">
            <thead>
              <tr>
                <th>Title</th>
                <th>Assigned To</th>
                <th>Priority</th>
                <th>Status</th>
                <th>Estimated Effort</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {tasks.map(task => (
                <tr key={task._id}>
                  <td>{task.title}</td>
                  <td>{task.assignedTo?.name || 'Unassigned'}</td>
                  <td>
                    <span className={`badge badge-${task.priority === 'High' ? 'danger' : task.priority === 'Medium' ? 'warning' : 'info'}`}>
                      {task.priority}
                    </span>
                  </td>
                  <td>
                    <span className={`badge badge-${task.status === 'Completed' ? 'success' : task.status === 'In Progress' ? 'info' : 'warning'}`}>
                      {task.status}
                    </span>
                  </td>
                  <td>{task.estimatedEffort} points</td>
                  <td>
                    <Link to={`/tasks/${task._id}`} className="btn btn-primary btn-sm">
                      View
                    </Link>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default SprintDetail;
